\documentclass[standalone]{article}
\usepackage{tikz}
\usetikzlibrary{positioning}

\begin{document}
\begin{tikzpicture}[font=\sffamily, every node/.style={inner sep=1pt}]
\tikzset{
  circ/.style={circle, draw, line width=0.6pt, minimum size=1.05cm, align=center},
  leaf/.style={draw, rectangle, line width=0.6pt, minimum width=1.4cm, minimum height=0.9cm, align=center}
}

% Root
\node[circ] (r) at (0,0) {63};

% Level 1 (horizontally flipped structure)
\node[circ] (n37) at (-3.2,-2.1) {37};
\node[circ] (n26) at (3.2,-2.1) {26};
\draw (r) -- (n37);
\draw (r) -- (n26);

% Level 2
\node[circ] (n19) at (-4.6,-4.2) {19};
\node[leaf] (i18) at (-1.9,-4.2) {I:18};
\draw (n37) -- (n19);
\draw (n37) -- (i18);

\node[circ] (n14) at (1.9,-4.2) {14};
\node[leaf] (a12) at (4.6,-4.2) {A:12};
\draw (n26) -- (n14);
\draw (n26) -- (a12);

% Level 3
\node[leaf] (m10) at (-5.8,-6.3) {M:10};
\node[leaf] (s9) at (-3.2,-6.3) {S:9};
\draw (n19) -- (m10);
\draw (n19) -- (s9);

\node[circ] (n7) at (1.9,-6.3) {7};
\node[leaf] (b7) at (0.0,-6.3) {B:7};
\draw (n14) -- (n7);
\draw (n14) -- (b7);

% Level 4
\node[leaf] (x5) at (1.9,-8.4) {X:5};
\node[leaf] (z2) at (4.6,-8.4) {Z:2};
\draw (n7) -- (x5);
\draw (n7) -- (z2);

\end{tikzpicture}
\end{document}

\documentclass[tikz,border=3pt]{standalone}
\usepackage{tikz}
\usetikzlibrary{positioning}

\begin{document}
\begin{tikzpicture}[
    every node/.style={font=\sffamily},
    circ/.style={circle,draw,minimum size=18mm,inner sep=0pt,fill=gray!20},
    leaf/.style={draw,rectangle,minimum width=28mm,minimum height=12mm,inner sep=2pt,fill=gray!20},
    line/.style={draw,thin}
]

% Nodes
\node[circ] (n63) at (0,0) {63};
\node[circ] (n26) at (-4,-2) {26};
\node[circ] (n37) at (4,-2) {37};
\node[leaf] (a12) at (-6,-4) {A:12};
\node[circ] (n14) at (-2.4,-4) {14};
\node[leaf] (b7) at (-4,-6) {B:7};
\node[circ] (n7) at (-1,-6) {7};
\node[leaf] (z2) at (-2.2,-8) {Z:2};
\node[leaf] (x5) at (0.2,-8) {X:5};
\node[leaf] (i18) at (2.3,-4) {I:18};
\node[circ] (n19) at (5.3,-4) {19};
\node[leaf] (s9) at (4,-6) {S:9};
\node[leaf] (m10) at (6.2,-6) {M:10};

% Edges
\draw[line] (n63) -- (n26);
\draw[line] (n63) -- (n37);
\draw[line] (n26) -- (a12);
\draw[line] (n26) -- (n14);
\draw[line] (n14) -- (b7);
\draw[line] (n14) -- (n7);
\draw[line] (n7) -- (z2);
\draw[line] (n7) -- (x5);
\draw[line] (n37) -- (i18);
\draw[line] (n37) -- (n19);
\draw[line] (n19) -- (s9);
\draw[line] (n19) -- (m10);

\end{tikzpicture}
\end{document}
